// Inverse sets z to the inverse of x in E6 and returns z
//
// if x == 0, sets and returns z = x
func (z *E6) Inverse(x *E6) *E6 {
	// Algorithm 17 from https://eprint.iacr.org/2010/354.pdf
	// step 9 is wrong in the paper it's t1-t4
	var t0, t1, t2, t3, t4, t5, t6, c0, c1, c2, d1, d2 E2
	t0.Square(&x.B0)
	t1.Square(&x.B1)
	t2.Square(&x.B2)
	t3.Mul(&x.B0, &x.B1)
	t4.Mul(&x.B0, &x.B2)
	t5.Mul(&x.B1, &x.B2)
	c0.MulByCubicNonResidue(&t5).Neg(&c0).Add(&c0, &t0)
	c1.MulByCubicNonResidue(&t2).Sub(&c1, &t3)
	c2.Sub(&t1, &t4)
	t6.Mul(&x.B0, &c0)
	d1.Mul(&x.B2, &c1)
	d2.Mul(&x.B1, &c2)
	d1.Add(&d1, &d2).MulByCubicNonResidue(&d1)
	t6.Add(&t6, &d1)
	t6.Inverse(&t6)
	z.B0.Mul(&c0, &t6)
	z.B1.Mul(&c1, &t6)
	z.B2.Mul(&c2, &t6)

	return z
}

// Exp sets z=xᵏ (mod q⁶) and returns it
func (z *E6) Exp(x E6, k *big.Int) *E6 {
	if k.IsInt64() {
		return z.ExpInt64(x, k.Int64())
	}

	e := k
	if k.Sign() == -1 {
		// negative k, we invert
		// if k < 0: xᵏ (mod q⁶) == (x⁻¹)ᵏ (mod q⁶)
		x.Inverse(&x)

		// we negate k in a temp big.Int since
		// Int.Bit(_) of k and -k is different
		e = bigIntPool.Get().(*big.Int)
		defer bigIntPool.Put(e)
		e.Neg(k)
	}

	// Iterate over the bytes of |k|, starting from the most-significant byte.
	// Skip leading zero bits of the first non-zero byte so we don't waste
	// squarings on bits above the most-significant 1.
	b := e.Bytes()
	if len(b) == 0 {
		return z.SetOne()
	}
	z.Set(&x)
	first := b[0]
	for j := bits.LeadingZeros8(first) + 1; j < 8; j++ {
		z.Square(z)
		if (first & (0b10000000 >> j)) != 0 {
			z.Mul(z, &x)
		}
	}
	for i := 1; i < len(b); i++ {
		w := b[i]
		for j := 0; j < 8; j++ {
			z.Square(z)
			if (w & (0b10000000 >> j)) != 0 {
				z.Mul(z, &x)
			}
		}
	}

	return z
}

// ExpInt64 sets z=xᵏ (mod q⁶) and returns it, where k is an int64
func (z *E6) ExpInt64(x E6, k int64) *E6 {
	if k == 0 {
		return z.SetOne()
	}

	exp := k
	if k < 0 {
		x.Inverse(&x)
		exp = -k // if k == math.MinInt64, -k overflows, but uint64(-k) is correct
	}

	z.Set(&x)

	// Use bits.Len64 to iterate only over significant bits
	for i := bits.Len64(uint64(exp)) - 2; i >= 0; i-- {
		z.Square(z)
		if (uint64(exp)>>uint(i))&1 != 0 {
			z.Mul(z, &x)
		}
	}

	return z
}

